// 1. Obtener el texto crudo de Gemini
const rawText = $input.first().json.output;

// 2. Limpiar los caracteres de markdown (```json y ```)
const cleanText = rawText.replace(/```json\n?/g, '').replace(/```/g, '').trim();

// 3. Convertir el texto a un objeto JSON real
const parsedJson = JSON.parse(cleanText);

// 4. Retornar el JSON limpio
return { json: parsedJson };

const items = $input.all();
const reports = items.map(item => item.json);

if (reports.length === 0) {
  return [{ 
    json: { 
      message: "❌ No se encontraron reportes asociados a ese ID." 
    } 
  }];
}

let response = "📋 *ESTADO DEL REPORTE*\n\n";

reports.forEach(report => {
  // Ajusta estos nombres según tus columnas exactas en Google Sheets
  const ticket = $input.first().json['Ticket  ID'] || report.ticket_id || "N/A";
  const tipoDaño = $input.first().json['Categoría'] || report.tipo_daño || "N/A";
  const severidad = $input.first().json.Prioridad || report.severidad || "N/A";
  const estado = $input.first().json['Estado Actual'] || report.estado || "N/A";
  const ubicacion = $input.first().json['Dirección'] || report.ubicacion || "N/A";

  response += `🎟 *Ticket:* ${ticket}\n`;
  response += `📍 *Ubicación:* ${ubicacion}\n`;
  response += `⚠️ *Daño:* ${tipoDaño}\n`;
  response += `🔴 *Severidad:* ${severidad}\n`;
  response += `🔄 *Estado:* ${estado}\n\n`;
});

return [{ 
  json: { 
    message: response,
    reportData: reports[0] // Mantiene los datos originales si los necesitas después
  } 
}];

// Supongamos que el base64 viene en:
// $json.imageBase64

const base64Image = $json.imageBase64;

// Eliminar prefijo si existe (data:image/png;base64,...)
const cleanBase64 = base64Image.replace(/^data:image/\w+;base64,/, '');

return [
  {
    json: {},
    binary: {
      image: {
        data: cleanBase64,
        mimeType: 'image/png',
        fileName: 'imagen.png',
      },
    },
  },
];

